// MARK: - Password Hashing Service

class PasswordHashingService {
    
    static let shared = PasswordHashingService()
    
    private let saltLength = 32
    private let hashIterations: UInt32 = 10000
    private let derivedKeyLength = 64
    
    private init() {}
    
    // Generate a cryptographically secure random salt
    func generateSalt() -> Data {
        var salt = Data(count: saltLength)
        salt.withUnsafeMutableBytes { bufferPointer in
            guard let baseAddress = bufferPointer.baseAddress else { return }
            _ = SecRandomCopyBytes(kSecRandomDefault, saltLength, baseAddress)
        }
        return salt
    }
    
    // Hash password using PBKDF2 with HMAC-SHA512
    func hashPassword(_ password: String, salt: Data) -> Data? {
        guard let passwordData = password.data(using: .utf8) else { return nil }
        
        var derivedKey = Data(count: derivedKeyLength)
        
        let result = derivedKey.withUnsafeMutableBytes { derivedKeyBytes in
            salt.withUnsafeBytes { saltBytes in
                passwordData.withUnsafeBytes { passwordBytes in
                    CCKeyDerivationPBKDF(
                        CCPBKDFAlgorithm(kCCPBKDF2),
                        passwordBytes.baseAddress?.assumingMemoryBound(to: Int8.self),
                        passwordData.count,
                        saltBytes.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        salt.count,
                        CCPseudoRandomAlgorithm(kCCPRFHmacAlgSHA512),
                        hashIterations,
                        derivedKeyBytes.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        derivedKeyLength
                    )
                }
            }
        }
        
        guard result == kCCSuccess else { return nil }
        return derivedKey
    }
    
    // Constant-time comparison to prevent timing attacks
    func secureCompare(_ a: Data, _ b: Data) -> Bool {
        guard a.count == b.count else { return false }
        var result: UInt8 = 0
        for i in 0..<a.count {
            result |= a[i] ^ b[i]
        }
        return result == 0
    }
}

