    // MARK: - Store Password
    
    enum PasswordError: Error, LocalizedError {
        case hashingFailed
        case storageFailed
        case entryNotFound
        case invalidData
        case passwordTooShort
        case passwordTooLong
        
        var errorDescription: String? {
            switch self {
            case .hashingFailed: return "Failed to hash password"
            case .storageFailed: return "Failed to store password"
            case .entryNotFound: return "Password entry not found"
            case .invalidData: return "Invalid stored data"
            case .passwordTooShort: return "Password must be at least 8 characters"
            case .passwordTooLong: return "Password must be less than 128 characters"
            }
        }
    }
    
    func storePassword(_ password: String, forIdentifier identifier: String) -> Result<Void, PasswordError> {
        // Validate password
        guard password.count >= 8 else { return .failure(.passwordTooShort) }
        guard password.count <= 128 else { return .failure(.passwordTooLong) }
        
        // Generate salt and hash
        let salt = hashingService.generateSalt()
        guard let hash = hashingService.hashPassword(password, salt: salt) else {
            return .failure(.hashingFailed)
        }
        
        let now = Date()
        let entry = StoredPasswordEntry(
            identifier: identifier,
            saltHex: salt.hexString,
            hashHex: hash.hexString,
            createdAt: now,
            updatedAt: now
        )
        
        // Save entry
        guard saveEntry(entry) else {
            return .failure(.storageFailed)
        }
        
        return .success(())
    }
    
    // MARK: - Verify Password (Offline)
    
    func verifyPassword(_ password: String, forIdentifier identifier: String) -> Result<Bool, PasswordError> {
        guard let entry = loadEntry(forIdentifier: identifier) else {
            return .failure(.entryNotFound)
        }
        
        guard let storedSalt = entry.salt, let storedHash = entry.hash else {
            return .failure(.invalidData)
        }
        
        guard let computedHash = hashingService.hashPassword(password, salt: storedSalt) else {
            return .failure(.hashingFailed)
        }
        
        let isValid = hashingService.secureCompare(storedHash, computedHash)
        return .success(isValid)
    }
    
    // MARK: - Update Password
    
    func updatePassword(oldPassword: String, newPassword: String, forIdentifier identifier: String) -> Result<Void, PasswordError> {
        // First verify old password
        let verifyResult = verifyPassword(oldPassword, forIdentifier: identifier)
        switch verifyResult {
        case .success(let isValid):
            guard isValid else { return .failure(.invalidData) }
        case .failure(let error):
            return .failure(error)
        }
        
        // Store new password
        return storePassword(newPassword, forIdentifier: identifier)
    }
    
    // MARK: - Delete Password
    
    func deletePassword(forIdentifier identifier: String) -> Bool {
