        return loadEntry(forIdentifier: identifier) != nil
    }
    
    // MARK: - Private Storage Helpers
    
    private func saveEntry(_ entry: StoredPasswordEntry) -> Bool {
        var entries = loadAllEntries()
        entries.removeAll { $0.identifier == entry.identifier }
        entries.append(entry)
