// MARK: - UITableViewDelegate & DataSource

extension PasswordStorageViewController: UITableViewDelegate, UITableViewDataSource {
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return entries.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "EntryCell", for: indexPath)
        cell.textLabel?.text = "🔑 \(entries[indexPath.row])"
        cell.textLabel?.font = UIFont.systemFont(ofSize: 15)
        cell.selectionStyle = .default
        return cell
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        identifierTextField.text = entries[indexPath.row]
        passwordTextField.becomeFirstResponder()
    }
    
    func tableView(_ tableView: UITableView, commit editingStyle: UITableViewCell.EditingStyle, forRowAt indexPath: IndexPath) {
        if editingStyle == .delete {
            let identifier = entries[indexPath.row]
            if passwordManager.deletePassword(forIdentifier: identifier) {
                entries.remove(at: indexPath.row)
                tableView.deleteRows(at: [indexPath], with: .fade)
                showStatus("🗑 Entry deleted for '\(identifier)'", isError: false)
                savedEntriesLabel.text = entries.isEmpty ? "Saved Entries (none)" : "Saved Entries (\(entries.count))"
            }
        }
    }
}

